 1	import * as React from 'react';
 2	import { IBM_SCALE_NAMESPACE } from '@odf/core/constants';
 3	import { EventModel, useCustomTranslation } from '@odf/shared';
 4	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 5	import { EventKind } from '@openshift-console/dynamic-plugin-sdk/lib/api/internal-types';
 6	import {
 7	  ActivityBody,
 8	  RecentEventsBody,
 9	} from '@openshift-console/dynamic-plugin-sdk-internal';
10	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
11	
12	const eventsResource = { isList: true, kind: EventModel.kind };
13	
14	const RecentEvent: React.FC = () => {
15	  const [data, loaded, loadError] =
16	    useK8sWatchResource<EventKind[]>(eventsResource);
17	  const filteredEvents = data?.filter(
18	    (event) => event.metadata.namespace === IBM_SCALE_NAMESPACE
19	  );
20	  return (
21	    <RecentEventsBody events={{ data: filteredEvents, loaded, loadError }} />
22	  );
23	};
24	const ActivityCard: React.FC<{}> = () => {
25	  const { t } = useCustomTranslation();
26	  return (
27	    <Card>
28	      <CardHeader>
29	        <CardTitle>{t('Activity')}</CardTitle>
30	      </CardHeader>
31	      <CardBody>
32	        <ActivityBody>
33	          <RecentEvent />
34	        </ActivityBody>
35	      </CardBody>
36	    </Card>
37	  );
38	};
39	
40	export default ActivityCard;

